// ─── Types ────────────────────────────────────────────────────────────────────

export interface OrderItem {
  id: number;
  name: string;
  category?: string;
  price: number;
  qty: number;
  subtotal: number;
}

export interface Order {
  id: string;
  type: 'dine-in' | 'pickup';
  tableId?: number;
  customerName: string;
  phone?: string;
  items: OrderItem[];
  subtotal: number;
  discount: number;
  total: number;
  payment: string;
  status: 'pending' | 'preparing' | 'prepared' | 'served' | 'completed';
  timestamp: string;
}

export interface Table {
  id: number;
  chairs: number;
  status: 'available' | 'occupied' | 'reserved';
  occupants: { name: string }[];
}

export interface MenuItem {
  id: number;
  category: string;
  name: string;
  desc: string;
  price: number;
  img?: string;
  badge?: string;
}

// ─── Keys ─────────────────────────────────────────────────────────────────────

const KEYS = {
  orders: 'fl_orders',
  tables: 'fl_tables',
  menu:   'fl_menu',
  pin:    'fl_owner_pin',
};

// ─── Helpers ──────────────────────────────────────────────────────────────────

function get<T>(key: string, fallback: T): T {
  if (typeof window === 'undefined') return fallback;
  try {
    const v = localStorage.getItem(key);
    return v ? JSON.parse(v) : fallback;
  } catch { return fallback; }
}

function set<T>(key: string, value: T): void {
  if (typeof window === 'undefined') return;
  localStorage.setItem(key, JSON.stringify(value));
}

// ─── Orders ───────────────────────────────────────────────────────────────────

export const getOrders  = (): Order[]          => get<Order[]>(KEYS.orders, []);
export const saveOrders = (orders: Order[])     => set(KEYS.orders, orders);

export function addOrder(order: Order) {
  const orders = getOrders();
  orders.push(order);
  saveOrders(orders);
}

export function updateOrderStatus(orderId: string, status: Order['status']) {
  const orders = getOrders();
  const idx = orders.findIndex(o => o.id === orderId);
  if (idx !== -1) { orders[idx].status = status; saveOrders(orders); }
}

// ─── Tables ───────────────────────────────────────────────────────────────────

export function getTables(): Table[] {
  const saved = get<Table[] | null>(KEYS.tables, null);
  if (saved) return saved;
  const defaults: Table[] = Array.from({ length: 15 }, (_, i) => ({
    id: i + 1, chairs: 4, status: 'available', occupants: [],
  }));
  set(KEYS.tables, defaults);
  return defaults;
}
export const saveTables = (tables: Table[]) => set(KEYS.tables, tables);

