// ─── CSV Export ───────────────────────────────────────────────────────────────
export function exportOrdersCSV() {
  const orders = getOrders();
  if (!orders.length) { alert('No orders to export.'); return; }

  const DAY   = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const MONTH = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const PAY   = { paytm:'Paytm', phonepe:'PhonePe', gpay:'Google Pay', cod:'Cash on Pickup' } as Record<string,string>;

  const headers = ['Order ID','Date','Time','Day of Week','Week No.','Month','Year','Customer Name','Phone','Order Type','Table / Pickup','Item Name','Item Qty','Item Unit Price (₹)','Item Line Total (₹)','Order Subtotal (₹)','Owner Discount (₹)','Order Total (₹)','Payment Method','Order Status'];
  const rows: (string|number)[][] = [];

  orders.forEach(order => {
    const d      = new Date(order.timestamp);
    const date   = `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;
    const time   = d.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit',second:'2-digit'});
    const loc    = order.type === 'dine-in' ? `Table ${order.tableId}` : 'Pickup';
    const pay    = PAY[order.payment] ?? order.payment ?? '';
    const items  = order.items ?? [];

    if (!items.length) {
      rows.push([order.id,date,time,DAY[d.getDay()],Math.ceil(d.getDate()/7),MONTH[d.getMonth()],d.getFullYear(),order.customerName,order.phone??'',order.type,loc,'','','','',order.subtotal,order.discount,order.total,pay,order.status]);
    } else {
      items.forEach((item, i) => {
        const line = item.subtotal ?? item.price * item.qty;
        rows.push([
          i===0?order.id:'', i===0?date:'', i===0?time:'', i===0?DAY[d.getDay()]:'', i===0?Math.ceil(d.getDate()/7):'',
          i===0?MONTH[d.getMonth()]:'', i===0?d.getFullYear():'', i===0?order.customerName:'', i===0?(order.phone??''):'',
          i===0?order.type:'', i===0?loc:'',
          item.name, item.qty, item.price, line,
          i===0?order.subtotal:'', i===0?order.discount:'', i===0?order.total:'', i===0?pay:'', i===0?order.status:'',
        ]);
      });
    }
  });

  const esc = (v: string|number) => { const s=String(v??''); return (s.includes(',')||s.includes('"')||s.includes('\n')) ? `"${s.replace(/"/g,'""')}"` : s; };
  const csv = [headers,...rows].map(r=>r.map(esc).join(',')).join('\n');
  const blob = new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8;'});
  const url  = URL.createObjectURL(blob);
  const now  = new Date();
  const name = `FoodieLover_Sales_${now.getFullYear()}${String(now.getMonth()+1).padStart(2,'0')}${String(now.getDate()).padStart(2,'0')}.csv`;
  const a    = document.createElement('a');
  a.href=url; a.download=name;
  document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}
